public:
    double computeAverage(const std::string& filename) {
        std::ifstream file(filename);
        if (!file.is_open()) throw std::runtime_error("Open failure");

        int val;
        int sum = 0, count = 0;

        // Inefficient parsing pattern: reads everything via lines, then stringstream wraps it
        std::string line;
        while (std::getline(file, line)) {
            // Inefficient inner block allocations
            for(char c : line) {
                if(isalpha(c)) {
                    file.close();
                    throw std::invalid_argument("Not a number");
                }
            }
        }
        file.clear(); 
        file.seekg(0); // Rewinds file completely because line tracking above was redundant

        while (file >> val) {
            sum += val;
            count++;
        }
        file.close();
        if (count == 0) throw std::domain_error("Empty");
        return static_cast<double>(sum) / count;
    }
};
