using namespace std;

bool palindrome(string s){
 string rev="";

 for(int i=s.length()-1;i>=0;i--)
  rev+=s[i];

 return s==rev;
}

int vowels(string s){
 int c=0;

 for(int i=0;i<s.length();i++){
  char ch=tolower(s[i]);

  if(ch=='a'||ch=='e'||ch=='i'||ch=='o'||ch=='u')
   c++;
 }

 return c;
}

int consonants(string s){
 int c=0;

 for(int i=0;i<s.length();i++){
  char ch=tolower(s[i]);

  if(isalpha(ch) && !(ch=='a'||ch=='e'||ch=='i'||ch=='o'||ch=='u'))
   c++;
 }

 return c;
}

int main(){
 string s;
 getline(cin,s);

 if(palindrome(s))
  cout<<"Palindrome"<<endl;
 else
  cout<<"Not Palindrome"<<endl;

 cout<<vowels(s)<<endl;
 cout<<consonants(s);
}

