#include <cmath>
using namespace std;

bool prime(int n){
 if(n<2)
  return false;

 for(int i=2;i<n;i++){
  if(n%i==0)
   return false;
 }

 return true;
}

bool armstrong(int n){
 int temp=n;
 int sum=0;

 while(temp>0){
  int digit=temp%10;
  sum+=digit*digit*digit;
  temp/=10;
 }

 return sum==n;
}

int main(){
 int n;
 cin>>n;

 cout<<(prime(n)?"Prime":"Not Prime")<<endl;
 cout<<(armstrong(n)?"Armstrong":"Not Armstrong");
}

