 for(int i=0;i<10;i++)
  cin >> arr[i];

 cin >> key;

 bubbleSort(arr,10);

 for(int i=0;i<10;i++)
  cout << arr[i] << " ";

 cout << endl;

 int pos = linearSearch(arr,10,key);

 if(pos != -1)
  cout << "Found at index " << pos;
 else
  cout << "Not Found";

 return 0;
}

