std::vector<std::pair<std::string, int>> sortWordsByFrequency(const std::vector<std::string>& words) {
    std::map<std::string, int> counts;
    for (const auto& w : words) {
        counts[w]++;
    }

    std::vector<std::pair<std::string, int>> result;
    for (const auto& pair : counts) {
        result.push_back(pair);
    }

    std::sort(result.begin(), result.end(), myComp);
    return result;
}

