void reverseArray(int *arr, int size){
 int *start = arr;
 int *end = arr + size - 1;

 while(start < end){
  int temp = *start;
  *start = *end;
  *end = temp;
  start++;
  end--;
 }
}

int sumArray(int *arr, int size){
 int sum = 0;
 for(int i=0;i<size;i++)
  sum += *(arr+i);
 return sum;
}

