bool isArmstrong(int n){
 int temp=n;
 int digits=0;
 int sum=0;

 while(temp>0){
  digits++;
  temp/=10;
 }

 temp=n;

 while(temp>0){
  int digit=temp%10;
  sum += pow(digit,digits);
  temp/=10;
 }

 return sum==n;
}

