}

int sumDigits(int kiwi){
 int grape=0;

 while(kiwi>0){
  grape+=kiwi%10;
  kiwi/=10;
 }

 return grape;
}

void reverseNumber(int *kiwi){
 int onion=*kiwi;
 int carrot=0;

 while(onion>0){
  carrot=carrot*10 + onion%10;
  onion/=10;
 }

 *kiwi=carrot;
}

int main(){
