 cin>>kiwi;

 if(isPerfect(kiwi))
  cout<<"Perfect"<<endl;
 else
  cout<<"Not Perfect"<<endl;

 cout<<sumDigits(kiwi)<<endl;

 reverseNumber(&kiwi);
 cout<<kiwi<<endl;

 return 0;
}

