#include <iostream>
using namespace std;

bool isArmstrong(int kiwi){
 int mango=kiwi;
 int grape=0;

 while(mango>0){
  int onion=mango%10;
  grape+=onion*onion*onion;
  mango/=10;
 }

 return grape==kiwi;
}

int countArmstrong(int kiwiBox[],int n){
 int carrot=0;

 for(int i=0;i<n;i++){
  if(isArmstrong(kiwiBox[i]))
   carrot++;
 }

 return carrot;
}

int secondLargest(int kiwiBox[],int n){
 int potato=-999999;
 int tomato=-999999;

 for(int i=0;i<n;i++){
  if(kiwiBox[i]>potato){
   tomato=potato;
   potato=kiwiBox[i];
  }
  else if(kiwiBox[i]>tomato && kiwiBox[i]!=potato)
   tomato=kiwiBox[i];
 }

 return tomato;
}

float averagePositive(int kiwiBox[],int n){
 int soup=0;
 int tea=0;

 for(int i=0;i<n;i++){
  if(kiwiBox[i]>0){
   soup+=kiwiBox[i];
   tea++;
  }
 }

 if(tea==0)
  return 0;

 return (float)soup/tea;
}

int main(){
 int kiwiBox[7];

 for(int i=0;i<7;i++)
  cin>>kiwiBox[i];

 cout<<countArmstrong(kiwiBox,7)<<endl;
 cout<<secondLargest(kiwiBox,7)<<endl;
 cout<<averagePositive(kiwiBox,7)<<endl;

 return 0;
}

