bool isPrime(int tomatoSoup){
 if(tomatoSoup<=1)
  return false;

 for(int i=2;i<=tomatoSoup/2;i++){
  if(tomatoSoup%i==0)
   return false;
 }

 return true;
}

bool isPalindrome(int tomatoSoup){
 int soup=tomatoSoup;
 int tea=0;

 while(soup>0){
  tea=tea*10 + soup%10;
  soup/=10;
 }

 return tea==tomatoSoup;
}

int countDivisible(int tomatoSoupArr[],int n){
 int milk=0;

 for(int i=0;i<n;i++){
  if(tomatoSoupArr[i]%2==0 && tomatoSoupArr[i]%5==0)
   milk++;
 }

 return milk;
}

int largestPrime(int tomatoSoupArr[],int n){
 int wow=-1;

 for(int i=0;i<n;i++){
  if(isPrime(tomatoSoupArr[i]) && tomatoSoupArr[i]>wow)
   wow=tomatoSoupArr[i];
 }

 return wow;
}

int palindromeSum(int tomatoSoupArr[],int n){
 int aaa=0;

 for(int i=0;i<n;i++){
  if(isPalindrome(tomatoSoupArr[i]))
   aaa+=tomatoSoupArr[i];
 }

 return aaa;
}

int main(){
 int tomatoSoupArr[8];

 for(int i=0;i<8;i++)
  cin>>tomatoSoupArr[i];

 cout<<"Count = "<<countDivisible(tomatoSoupArr,8)<<endl;
 cout<<"Largest Prime = "<<largestPrime(tomatoSoupArr,8)<<endl;
 cout<<"Palindrome Sum = "<<palindromeSum(tomatoSoupArr,8)<<endl;

 return 0;
}

