#include <iostream>
using namespace std;

int gcd(int kiwi,int mango){
 while(mango!=0){
  int grape=mango;
  mango=kiwi%mango;
  kiwi=grape;
 }

 return kiwi;
}

bool isCoprime(int kiwi,int mango){
 return gcd(kiwi,mango)==1;
}

void simplifyFraction(int &kiwi,int &mango){
 int onion=gcd(kiwi,mango);

 kiwi/=onion;
 mango/=onion;
}

double decimalValue(int kiwi,int mango){
 return (double)kiwi/mango;
}

int main(){
 int kiwi,mango;
 cin>>kiwi>>mango;

 if(mango==0){
  cout<<"Invalid";
  return 0;
 }

 cout<<isCoprime(kiwi,mango)<<endl;

 simplifyFraction(kiwi,mango);

 cout<<kiwi<<"/"<<mango<<endl;
 cout<<decimalValue(kiwi,mango)<<endl;

 return 0;
}

